import{c as s,Q as n,j as e,m as l}from"./chunks/framework.rlpw0eGz.js";const u=JSON.parse('{"title":"代码抽象：好的抽象与过度设计","description":"关于代码抽象程度的探索思考，讨论好抽象的特征、过度设计的信号、以及实用的判断框架","frontmatter":{"title":"代码抽象：好的抽象与过度设计","description":"关于代码抽象程度的探索思考，讨论好抽象的特征、过度设计的信号、以及实用的判断框架","date":"2026-06-02T00:00:00.000Z"},"headers":[],"relativePath":"notes/代码抽象：好的抽象与过度设计.md","filePath":"notes/代码抽象：好的抽象与过度设计.md","lastUpdated":null}'),t={name:"notes/代码抽象：好的抽象与过度设计.md"};function p(r,a,o,i,c,d){return n(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="代码抽象-好的抽象与过度设计" tabindex="-1">代码抽象：好的抽象与过度设计 <a class="header-anchor" href="#代码抽象-好的抽象与过度设计" aria-label="Permalink to &quot;代码抽象：好的抽象与过度设计&quot;">​</a></h1><p class="note-date">2026-06-02</p><h2 id="结论速查" tabindex="-1">结论速查 <a class="header-anchor" href="#结论速查" aria-label="Permalink to &quot;结论速查&quot;">​</a></h2><h3 id="好抽象的-5-条标准" tabindex="-1">好抽象的 5 条标准 <a class="header-anchor" href="#好抽象的-5-条标准" aria-label="Permalink to &quot;好抽象的 5 条标准&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>标准</th><th>一句话判断</th></tr></thead><tbody><tr><td>1</td><td><strong>单一职责</strong></td><td>这个类/方法能用一句话说清楚它在做什么</td></tr><tr><td>2</td><td><strong>开闭原则</strong></td><td>加功能只需新增文件，不修改已有代码</td></tr><tr><td>3</td><td><strong>接口稳定</strong></td><td>换实现类时，调用方代码不用跟着改</td></tr><tr><td>4</td><td><strong>测试友好</strong></td><td>能 mock 下层，独立验证当前层</td></tr><tr><td>5</td><td><strong>名字即文档</strong></td><td>看函数签名就知道行为，不需要看实现</td></tr></tbody></table><h3 id="过度设计的-5-个信号" tabindex="-1">过度设计的 5 个信号 <a class="header-anchor" href="#过度设计的-5-个信号" aria-label="Permalink to &quot;过度设计的 5 个信号&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>信号</th><th>典型表现</th></tr></thead><tbody><tr><td>1</td><td><strong>为未来预留</strong></td><td>&quot;现在只有一个实现，但先抽接口&quot;——YAGNI</td></tr><tr><td>2</td><td><strong>层数过多</strong></td><td>跳转追踪超过 2-3 层</td></tr><tr><td>3</td><td><strong>强行消除重复</strong></td><td>代码相似但语义不同，合并后参数爆炸</td></tr><tr><td>4</td><td><strong>框架化</strong></td><td>if-else 能解决的问题套上工厂+策略+装饰器</td></tr><tr><td>5</td><td><strong>抽象泄漏</strong></td><td>调用方必须了解内部实现才能正确使用</td></tr></tbody></table><h3 id="决策框架速查" tabindex="-1">决策框架速查 <a class="header-anchor" href="#决策框架速查" aria-label="Permalink to &quot;决策框架速查&quot;">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span>Rule of Three：同一模式出现 3 次之前，不要抽象</span></span>
<span class="line"><span>成本收益：这个抽象减少的成本 &gt; 引入的成本？</span></span>
<span class="line"><span>自底向上：写完具体实现再提取，而非先画 UML 再编码</span></span>
<span class="line"><span>按层分级：基础设施层可多抽象，UI 层少用模式</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="抽象解决的四个问题" tabindex="-1">抽象解决的四个问题 <a class="header-anchor" href="#抽象解决的四个问题" aria-label="Permalink to &quot;抽象解决的四个问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>本质</th><th>典型手段</th></tr></thead><tbody><tr><td><strong>消除重复</strong></td><td>相同的代码只写一次</td><td>函数提取、基类、模板方法</td></tr><tr><td><strong>隔离变化</strong></td><td>调用方不受实现变更影响</td><td>接口、策略模式、适配器</td></tr><tr><td><strong>降低认知负担</strong></td><td>隐藏细节，暴露简洁接口</td><td>Facade、封装、分层</td></tr><tr><td><strong>提升表达力</strong></td><td>代码读起来像业务语言</td><td>领域模型、命名、DSL</td></tr></tbody></table><p>这四条是判断&quot;是否应该抽象&quot;的底层出发点。在设计和评审时，问自己：<strong>这个抽象解决了四个问题中的哪一个？如果哪个都不是，那就不该做。</strong></p><hr><h2 id="解析说明" tabindex="-1">解析说明 <a class="header-anchor" href="#解析说明" aria-label="Permalink to &quot;解析说明&quot;">​</a></h2><h3 id="一、抽象的本质" tabindex="-1">一、抽象的本质 <a class="header-anchor" href="#一、抽象的本质" aria-label="Permalink to &quot;一、抽象的本质&quot;">​</a></h3><p>抽象是<strong>简化认知负担</strong>的工具——隐藏不需要关心的细节，暴露稳定的接口。</p><p>核心矛盾：</p><ul><li>抽象太少 → 重复代码多、散弹式修改、理解全局困难</li><li>抽象太多 → 间接层堆叠、追踪逻辑绕路、简单事情复杂化</li></ul><p>好的抽象让你觉得&quot;本该如此&quot;；坏的抽象让你觉得&quot;为什么要绕一圈&quot;。</p><hr><h3 id="二、好抽象的-5-条标准详解" tabindex="-1">二、好抽象的 5 条标准详解 <a class="header-anchor" href="#二、好抽象的-5-条标准详解" aria-label="Permalink to &quot;二、好抽象的 5 条标准详解&quot;">​</a></h3><h4 id="_1-单一职责-srp" tabindex="-1">1. 单一职责（SRP） <a class="header-anchor" href="#_1-单一职责-srp" aria-label="Permalink to &quot;1. 单一职责（SRP）&quot;">​</a></h4><p>每个抽象层只做一件事。判断方式：能不能用一句话说清这个类/方法做什么。</p><div class="language-java line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="color:#7F848E;font-style:italic;">// 坏：一个类管解析、校验、持久化、通知</span></span>
<span class="line"><span style="color:#C678DD;">class</span><span style="color:#E5C07B;"> DataProcessor</span><span style="color:#ABB2BF;"> {}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 好：各司其职</span></span>
<span class="line"><span style="color:#C678DD;">class</span><span style="color:#E5C07B;"> XmlParser</span><span style="color:#ABB2BF;"> {}</span></span>
<span class="line"><span style="color:#C678DD;">class</span><span style="color:#E5C07B;"> Validator</span><span style="color:#ABB2BF;"> {}</span></span>
<span class="line"><span style="color:#C678DD;">class</span><span style="color:#E5C07B;"> Repository</span><span style="color:#ABB2BF;"> {}</span></span>
<span class="line"><span style="color:#C678DD;">class</span><span style="color:#E5C07B;"> Notifier</span><span style="color:#ABB2BF;"> {}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h4 id="_2-开闭原则-ocp" tabindex="-1">2. 开闭原则（OCP） <a class="header-anchor" href="#_2-开闭原则-ocp" aria-label="Permalink to &quot;2. 开闭原则（OCP）&quot;">​</a></h4><p><strong>对扩展开放，对修改关闭</strong>。加功能时不需要改已有代码。</p><div class="language-java line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="color:#7F848E;font-style:italic;">// 坏：加支付方式要改 if-else</span></span>
<span class="line"><span style="color:#C678DD;">if</span><span style="color:#E06C75;"> (</span><span style="color:#E5C07B;">type</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">equals</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&quot;alipay&quot;</span><span style="color:#ABB2BF;">)</span><span style="color:#E06C75;">) { </span><span style="color:#ABB2BF;">...</span><span style="color:#E06C75;"> }</span></span>
<span class="line"><span style="color:#C678DD;">else</span><span style="color:#C678DD;"> if</span><span style="color:#E06C75;"> (</span><span style="color:#E5C07B;">type</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">equals</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&quot;wechat&quot;</span><span style="color:#ABB2BF;">)</span><span style="color:#E06C75;">) { </span><span style="color:#ABB2BF;">...</span><span style="color:#E06C75;"> }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 好：新增实现类</span></span>
<span class="line"><span style="color:#C678DD;">interface</span><span style="color:#E5C07B;"> PaymentStrategy</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#C678DD;">    void</span><span style="color:#61AFEF;"> pay</span><span style="color:#ABB2BF;">(</span><span style="color:#E5C07B;">Order</span><span style="color:#E06C75;font-style:italic;"> order</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h4 id="_3-接口稳定" tabindex="-1">3. 接口稳定 <a class="header-anchor" href="#_3-接口稳定" aria-label="Permalink to &quot;3. 接口稳定&quot;">​</a></h4><p>一个好的抽象，接口不会因为下层实现变更而频繁变化。</p><p><strong>判断方法</strong>：改了实现类之后，调用方代码是否需要跟着改？需要 → 抽象层泄漏了细节。</p><h4 id="_4-测试友好" tabindex="-1">4. 测试友好 <a class="header-anchor" href="#_4-测试友好" aria-label="Permalink to &quot;4. 测试友好&quot;">​</a></h4><p>好的抽象应该让单元测试容易写。你能够 mock 掉下层依赖，独立验证当前层的逻辑。</p><p>如果写测试变得困难（层层都需要 mock、初始化复杂），说明抽象有问题。</p><h4 id="_5-名字即文档" tabindex="-1">5. 名字即文档 <a class="header-anchor" href="#_5-名字即文档" aria-label="Permalink to &quot;5. 名字即文档&quot;">​</a></h4><div class="language-java line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="color:#7F848E;font-style:italic;">// 坏：不知道在做什么</span></span>
<span class="line"><span style="color:#C678DD;">void</span><span style="color:#61AFEF;"> process</span><span style="color:#E06C75;">(</span><span style="color:#E5C07B;">String</span><span style="color:#E06C75;"> data)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 好：看名字就知道意图</span></span>
<span class="line"><span style="color:#C678DD;">void</span><span style="color:#61AFEF;"> validateAndSave</span><span style="color:#E06C75;">(</span><span style="color:#E5C07B;">UserInput</span><span style="color:#E06C75;"> input)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>一个好名字的抽象方法，基本不需要注释。需要注释来解释的命名，是抽象不到位的信号。</p><hr><h3 id="三、过度设计的-5-个信号详解" tabindex="-1">三、过度设计的 5 个信号详解 <a class="header-anchor" href="#三、过度设计的-5-个信号详解" aria-label="Permalink to &quot;三、过度设计的 5 个信号详解&quot;">​</a></h3><h4 id="_1-为-未来可能-预留" tabindex="-1">1. 为&quot;未来可能&quot;预留 <a class="header-anchor" href="#_1-为-未来可能-预留" aria-label="Permalink to &quot;1. 为&quot;未来可能&quot;预留&quot;">​</a></h4><p>&quot;现在虽然只有一个实现，但先抽接口，以后可能会有多种实现。&quot;</p><p><strong>现实</strong>：大多数&quot;以后可能&quot;永远不会来。YAGNI 原则（You Ain&#39;t Gonna Need It）是防范这个的最经典法则。</p><h4 id="_2-抽象层数过多" tabindex="-1">2. 抽象层数过多 <a class="header-anchor" href="#_2-抽象层数过多" aria-label="Permalink to &quot;2. 抽象层数过多&quot;">​</a></h4><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span>Controller → Service → ServiceImpl → AbstractService → BaseServiceImpl → ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>每多一层，开发时就要多跳转追踪一次。超过 2-3 层的抽象链通常值得质疑。</p><h4 id="_3-强行消除重复" tabindex="-1">3. 强行消除重复 <a class="header-anchor" href="#_3-强行消除重复" aria-label="Permalink to &quot;3. 强行消除重复&quot;">​</a></h4><p>两段代码只是长得像，但语义不同——强行合并成一个通用函数，结果参数爆炸：</p><div class="language-java line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="color:#7F848E;font-style:italic;">// 坏：参数多到看不懂意图</span></span>
<span class="line"><span style="color:#61AFEF;">process</span><span style="color:#E06C75;">(type</span><span style="color:#ABB2BF;">,</span><span style="color:#E06C75;"> mode</span><span style="color:#ABB2BF;">,</span><span style="color:#E06C75;"> flag</span><span style="color:#ABB2BF;">,</span><span style="color:#E06C75;"> isSpecial</span><span style="color:#ABB2BF;">,</span><span style="color:#E06C75;"> callback</span><span style="color:#ABB2BF;">,</span><span style="color:#E06C75;"> config)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 好：允许少量重复，保持语义清晰</span></span>
<span class="line"><span style="color:#61AFEF;">processNormalOrder</span><span style="color:#E06C75;">(order)</span></span>
<span class="line"><span style="color:#61AFEF;">processSpecialOrder</span><span style="color:#E06C75;">(order)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>关键区分</strong>：偶然重复 vs 本质重复。偶然重复只是碰巧长得像，强行抽象会创造错误的概念耦合。</p><h4 id="_4-框架化思维" tabindex="-1">4. 框架化思维 <a class="header-anchor" href="#_4-框架化思维" aria-label="Permalink to &quot;4. 框架化思维&quot;">​</a></h4><p>把一个小功能套上完整的设计模式堆叠（工厂 + 策略 + 装饰器 + 观察者），实际只需要一行判断。</p><h4 id="_5-抽象泄漏" tabindex="-1">5. 抽象泄漏 <a class="header-anchor" href="#_5-抽象泄漏" aria-label="Permalink to &quot;5. 抽象泄漏&quot;">​</a></h4><p>接口声称&quot;使用简单&quot;，但调用方必须了解内部实现细节才能正确使用：</p><div class="language-java line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="color:#7F848E;font-style:italic;">// 看起来简单，但调用方需要了解 cache 过期策略才能避免 bug</span></span>
<span class="line"><span style="color:#E5C07B;">cache</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">put</span><span style="color:#ABB2BF;">(key, value);</span></span>
<span class="line"><span style="color:#E5C07B;">cache</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">invalidate</span><span style="color:#ABB2BF;">(key);</span><span style="color:#7F848E;font-style:italic;">  // 必须手动调用，否则数据不一致</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><hr><h3 id="四、代码审查对照表" tabindex="-1">四、代码审查对照表 <a class="header-anchor" href="#四、代码审查对照表" aria-label="Permalink to &quot;四、代码审查对照表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>良好抽象 ✅</th><th>过度设计 ❌</th></tr></thead><tbody><tr><td>改动成本</td><td>加功能只需新增文件</td><td>加功能要改 3+ 个文件</td></tr><tr><td>阅读成本</td><td>5 秒理解类职责</td><td>跳转 4 层才找到实际逻辑</td></tr><tr><td>测试成本</td><td>1-2 个测试类</td><td>层层 mock，测试比业务复杂</td></tr><tr><td>命名清晰度</td><td>看签名就知道做什么</td><td>看了签名还要看实现</td></tr><tr><td>耦合度</td><td>依赖稳定接口</td><td>抽象层间有隐式耦合</td></tr><tr><td>重复容忍度</td><td>允许少量重复</td><td>追求零重复，创造奇怪抽象</td></tr></tbody></table><hr><h3 id="五、实战判断框架" tabindex="-1">五、实战判断框架 <a class="header-anchor" href="#五、实战判断框架" aria-label="Permalink to &quot;五、实战判断框架&quot;">​</a></h3><h4 id="rule-of-three-三次原则" tabindex="-1">Rule of Three（三次原则） <a class="header-anchor" href="#rule-of-three-三次原则" aria-label="Permalink to &quot;Rule of Three（三次原则）&quot;">​</a></h4><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span>第 1 次出现 → 直接写</span></span>
<span class="line"><span>第 2 次出现 → 观察，不急于抽象</span></span>
<span class="line"><span>第 3 次出现 → 认真考虑提取</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>防止&quot;为消除两次相似就引入抽象&quot;的冲动。</p><h4 id="自底向上-推荐-vs-自顶向下" tabindex="-1">自底向上（推荐）vs 自顶向下 <a class="header-anchor" href="#自底向上-推荐-vs-自顶向下" aria-label="Permalink to &quot;自底向上（推荐）vs 自顶向下&quot;">​</a></h4><p><strong>推荐自底向上</strong>：先写具体实现，感受到重复或复杂度后，再自然提取抽象。</p><p>避免自顶向下：先画好 UML 再编码。这种方式在需求不确定时最容易导致过度设计。</p><h4 id="成本收益分析" tabindex="-1">成本收益分析 <a class="header-anchor" href="#成本收益分析" aria-label="Permalink to &quot;成本收益分析&quot;">​</a></h4><p>每引入一个新抽象，问三个问题：</p><ol><li><strong>这个抽象减少了什么成本？</strong>（修改成本 / 理解成本 / 测试成本）</li><li><strong>引入了什么新成本？</strong>（间接层数 / 学习曲线 / 文件数量）</li><li><strong>净收益是正的还是负的？</strong></li></ol><p>如果净收益不明显，不要抽象。</p><h4 id="按层级划界" tabindex="-1">按层级划界 <a class="header-anchor" href="#按层级划界" aria-label="Permalink to &quot;按层级划界&quot;">​</a></h4><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span>基础设施层（DB/网络/缓存） → 抽象收益大，可多设计</span></span>
<span class="line"><span>业务逻辑层               → 适度抽象，避免过度</span></span>
<span class="line"><span>界面层（UI/API）         → 简单直接，少用模式</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>越靠近底层，抽象收益越明显；越靠近 UI，抽象成本越高。</p><hr><h3 id="六、面试回答模板" tabindex="-1">六、面试回答模板 <a class="header-anchor" href="#六、面试回答模板" aria-label="Permalink to &quot;六、面试回答模板&quot;">​</a></h3><p>被问到&quot;什么时候该抽象&quot;时，三个要点：</p><ol><li><strong>代码真正出现了重复</strong>（Rule of Three 验证）</li><li><strong>抽象能降低单元测试的复杂度</strong></li><li><strong>当下的业务边界清楚，不为不确定的未来铺路</strong></li></ol><p>能说清这三条，证明有工程判断力，不只是背设计模式。</p><hr><h3 id="七、延伸-好抽象的特征——手绘图" tabindex="-1">七、延伸：好抽象的特征——手绘图 <a class="header-anchor" href="#七、延伸-好抽象的特征——手绘图" aria-label="Permalink to &quot;七、延伸：好抽象的特征——手绘图&quot;">​</a></h3><p>抽象与细节的关系：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span>         信息密度</span></span>
<span class="line"><span>            ↑</span></span>
<span class="line"><span>   过度设计  |  ✗  间接层多、参数爆炸</span></span>
<span class="line"><span>   (高密度)  |</span></span>
<span class="line"><span>            |</span></span>
<span class="line"><span>    良好抽象 |  ✅  精简、稳定、意图清晰</span></span>
<span class="line"><span>            |</span></span>
<span class="line"><span>    没有抽象 |  ⚠   重复代码、散弹修改</span></span>
<span class="line"><span>            +——————————————→ 灵活性/可扩展性</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>理想位置在中间偏左：<strong>足够简单能理解，足够灵活能扩展</strong>。</p>`,81)])])}const h=s(t,[["render",p]]);export{u as __pageData,h as default};
